package com.synexis.management_service.security;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.http.HttpMethod;
import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configuration.WebSecurityCustomizer;
import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
import org.springframework.security.config.annotation.web.configurers.HeadersConfigurer;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.config.Customizer;

/**
 * Spring Security setup for the API: which URLs are anonymous, CSRF policy, and
 * the password hashing bean used when
 * saving users.
 *
 * <p>
 * How it works: {@link #securityFilterChain(HttpSecurity)} disables CSRF
 * (typical for stateless JSON APIs) and
 * allows unauthenticated access to {@code /ping}, paths under
 * {@code /register/}, the H2 console, and {@code OPTIONS}
 * preflight; everything else requires an authenticated principal.
 * {@link #passwordEncoder()} is used by {@link
 * com.synexis.management_service.service.impl.AuthServiceImpl AuthService} for
 * encoding and verification.
 */
@Configuration
@EnableWebSecurity
@EnableMethodSecurity
public class SecurityConfig {

    /**
     * Omite por completo el filtro de seguridad en estas rutas (evita 403 cuando
     * {@code permitAll} no coincide con el
     * {@code RequestMatcher} de MVC en algunos entornos). Los métodos del
     * controlador no influyen en la URL: solo
     * importan las rutas declaradas en {@code @PostMapping} / {@code @GetMapping}.
     */
    @Bean
    public WebSecurityCustomizer webSecurityCustomizer() {
        return web -> web.ignoring()
                .requestMatchers("/ping", "/register/**");
    }

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http.csrf(AbstractHttpConfigurer::disable)
                .headers(headers -> headers.frameOptions(HeadersConfigurer.FrameOptionsConfig::disable))
                .authorizeHttpRequests(
                        auth -> auth
                                .requestMatchers(HttpMethod.OPTIONS, "/**").permitAll()
                                .requestMatchers("/ping", "/register/**").permitAll()
                                .anyRequest().authenticated())
                .oauth2ResourceServer(oauth2 -> oauth2
                        .jwt(Customizer.withDefaults()));
        return http.build();
    }

    /**
     * BCrypt strength default (10). Used to hash passwords before storing
     * {@code password_hash} in the database.
     */
    @Bean
    public PasswordEncoder passwordEncoder() {
        return new BCryptPasswordEncoder();
    }
}

package com.synexis.management_service.security;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.http.HttpMethod;
import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configuration.WebSecurityCustomizer;
import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
import org.springframework.security.config.annotation.web.configurers.HeadersConfigurer;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.config.Customizer;

/**
 * Spring Security setup for the API: which URLs are anonymous, CSRF policy, and
 * the password hashing bean used when
 * saving users.
 *
 * <p>
 * How it works: {@link #securityFilterChain(HttpSecurity)} disables CSRF
 * (typical for stateless JSON APIs) and
 * allows unauthenticated access to {@code /ping}, paths under
 * {@code /register/}, the H2 console, and {@code OPTIONS}
 * preflight; everything else requires an authenticated principal.
 * {@link #passwordEncoder()} is used by {@link
 * com.synexis.management_service.service.impl.AuthServiceImpl AuthService} for
 * encoding and verification.
 */
@Configuration
@EnableWebSecurity
@EnableMethodSecurity
public class SecurityConfig {

    /**
     * Omite por completo el filtro de seguridad en estas rutas (evita 403 cuando
     * {@code permitAll} no coincide con el
     * {@code RequestMatcher} de MVC en algunos entornos). Los métodos del
     * controlador no influyen en la URL: solo
     * importan las rutas declaradas en {@code @PostMapping} / {@code @GetMapping}.
     */
    @Bean
    public WebSecurityCustomizer webSecurityCustomizer() {
        return web -> web.ignoring()
                .requestMatchers(
                        "/ping",
                        "/register/**",
                        "/api/auth/**",
                        "/api/clients/register/client",
                        "/api/partners/register/partner");
    }

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http.csrf(AbstractHttpConfigurer::disable)
                .headers(headers -> headers.frameOptions(HeadersConfigurer.FrameOptionsConfig::disable))
                .authorizeHttpRequests(
                        auth -> auth
                                .requestMatchers(HttpMethod.OPTIONS, "/**").permitAll()
                                .requestMatchers(
                                        "/ping",
                                        "/register/**",
                                        "/api/auth/**",
                                        "/api/clients/register/client",
                                        "/api/partners/register/partner").permitAll()
                                .anyRequest().authenticated())
                .oauth2ResourceServer(oauth2 -> oauth2
                        .jwt(Customizer.withDefaults()));
        return http.build();
    }

    /**
     * BCrypt strength default (10). Used to hash passwords before storing
     * {@code password_hash} in the database.
     */
    @Bean
    public PasswordEncoder passwordEncoder() {
        return new BCryptPasswordEncoder();
    }
}

package com.synexis.management_service.service;

import com.synexis.management_service.dto.response.LoginResponse;

public interface LoginService {

    LoginResponse loginClient(String email, String password);

    LoginResponse loginPartner(String email, String password);
}

package com.synexis.management_service.service.impl;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.synexis.management_service.dto.response.LoginResponse;
import com.synexis.management_service.entity.Client;
import com.synexis.management_service.entity.Partner;
import com.synexis.management_service.exception.InvalidCredentialsException;
import com.synexis.management_service.exception.KeycloakUserCreationException;
import com.synexis.management_service.exception.WrongPasswordException;
import com.synexis.management_service.repository.ClientRepository;
import com.synexis.management_service.repository.PartnerRepository;
import com.synexis.management_service.service.LoginService;
import java.io.IOException;
import java.net.URI;
import java.net.URLEncoder;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.nio.charset.StandardCharsets;
import org.springframework.stereotype.Service;

@Service
public class LoginServiceImpl implements LoginService {

    private static final String KEYCLOAK_URL = "http://localhost:8085";
    private static final String REALM = "synexis";
    private static final String CLIENT_ID = "telepresence";
    private static final String CLIENT_SECRET = "wO8qciPyigPvlYPQAX3wzft18wa1lqv6";

    private final ClientRepository clientRepository;
    private final PartnerRepository partnerRepository;
    private final ObjectMapper objectMapper = new ObjectMapper();
    private final HttpClient httpClient = HttpClient.newHttpClient();

    public LoginServiceImpl(
            ClientRepository clientRepository,
            PartnerRepository partnerRepository) {
        this.clientRepository = clientRepository;
        this.partnerRepository = partnerRepository;
    }

    @Override
    public LoginResponse loginClient(String email, String password) {
        String normalizedEmail = email.trim().toLowerCase();
        Client client = clientRepository.findByEmailIgnoreCase(normalizedEmail)
                .orElseThrow(InvalidCredentialsException::new);

        TokenResult token = requestToken(normalizedEmail, password);
        return new LoginResponse(
                token.accessToken,
                token.refreshToken,
                token.tokenType,
                token.expiresIn,
                client.getId(),
                client.getEmail(),
                client.getName(),
                client.getRole().name());
    }

    @Override
    public LoginResponse loginPartner(String email, String password) {
        String normalizedEmail = email.trim().toLowerCase();
        Partner partner = partnerRepository.findByEmailIgnoreCase(normalizedEmail)
                .orElseThrow(InvalidCredentialsException::new);

        TokenResult token = requestToken(normalizedEmail, password);
        return new LoginResponse(
                token.accessToken,
                token.refreshToken,
                token.tokenType,
                token.expiresIn,
                partner.getId(),
                partner.getEmail(),
                partner.getName(),
                partner.getRole().name());
    }

    private TokenResult requestToken(String email, String password) {
        String formBody = "client_id=" + encode(CLIENT_ID)
                + "&client_secret=" + encode(CLIENT_SECRET)
                + "&grant_type=password"
                + "&username=" + encode(email)
                + "&password=" + encode(password);

        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(KEYCLOAK_URL + "/realms/" + REALM + "/protocol/openid-connect/token"))
                .header("Content-Type", "application/x-www-form-urlencoded")
                .POST(HttpRequest.BodyPublishers.ofString(formBody))
                .build();

        try {
            HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());
            if (response.statusCode() == 200) {
                JsonNode node = objectMapper.readTree(response.body());
                return new TokenResult(
                        node.path("access_token").asText(),
                        node.path("refresh_token").asText(),
                        node.path("token_type").asText(),
                        node.path("expires_in").asLong());
            }
            if (response.statusCode() == 400 || response.statusCode() == 401) {
                throw new WrongPasswordException();
            }
            throw new KeycloakUserCreationException(
                    "Error de autenticacion en Keycloak. Status: " + response.statusCode());
        } catch (InterruptedException ex) {
            Thread.currentThread().interrupt();
            throw new KeycloakUserCreationException("No se pudo validar el login con Keycloak: " + ex.getMessage());
        } catch (IOException ex) {
            throw new KeycloakUserCreationException("No se pudo validar el login con Keycloak: " + ex.getMessage());
        }
    }

    private String encode(String value) {
        return URLEncoder.encode(value, StandardCharsets.UTF_8);
    }

    private static final class TokenResult {
        private final String accessToken;
        private final String refreshToken;
        private final String tokenType;
        private final long expiresIn;

        private TokenResult(String accessToken, String refreshToken, String tokenType, long expiresIn) {
            this.accessToken = accessToken;
            this.refreshToken = refreshToken;
            this.tokenType = tokenType;
            this.expiresIn = expiresIn;
        }
    }
}

package com.synexis.management_service.service.impl;

import com.synexis.management_service.dto.request.RegisterPartnerRequest;
import com.synexis.management_service.dto.response.RegisterPartnerResponse;
import com.synexis.management_service.entity.Area;
import com.synexis.management_service.entity.Partner;
import com.synexis.management_service.entity.PartnerAvailabilityStatus;
import com.synexis.management_service.entity.UserLanguage;
import com.synexis.management_service.entity.UserRole;
import com.synexis.management_service.exception.EmailAlreadyExistsException;
import com.synexis.management_service.exception.KeycloakUserCreationException;
import com.synexis.management_service.repository.PartnerRepository;
import com.synexis.management_service.service.AreaService;
import com.synexis.management_service.service.PartnerService;

import jakarta.ws.rs.core.Response;

import java.time.Instant;
import java.util.List;

import org.keycloak.admin.client.Keycloak;
import org.keycloak.representations.idm.CredentialRepresentation;
import org.keycloak.representations.idm.RoleRepresentation;
import org.keycloak.representations.idm.UserRepresentation;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * Handles partner registration and related business operations.
 *
 * This implementation persists partner data to the local database and
 * integrates with Keycloak for identity management, password setup, and role
 * assignment.
 *
 * It also enforces uniqueness checks and normalizes user input.
 */
@Service
public class PartnerServiceImpl implements PartnerService {

    private String keycloakRealm = "synexis";

    private final PartnerRepository partnerRepository;
    private final Keycloak keycloak;
    private final AreaService areaService;

    public PartnerServiceImpl(PartnerRepository partnerRepository, Keycloak keycloak, AreaService areaService) {
        this.partnerRepository = partnerRepository;
        this.keycloak = keycloak;
        this.areaService = areaService;
    }

    @Override
    @Transactional
    public RegisterPartnerResponse registerPartner(RegisterPartnerRequest request) {

        String normalizedEmail = request.email().trim().toLowerCase();

        if (partnerRepository.existsByEmailIgnoreCase(normalizedEmail)) {
            throw new EmailAlreadyExistsException(normalizedEmail);
        }

        // 1. CREATE USER IN KEYCLOAK
        UserRepresentation user = new UserRepresentation();
        user.setUsername(normalizedEmail);
        user.setEmail(normalizedEmail);
        user.setEnabled(true);
        user.setFirstName(request.name().trim());
        user.setLastName(request.name().trim());
        user.setEmailVerified(true);

        Response response = keycloak.realm(keycloakRealm).users().create(user);

        if (response.getStatus() != 201) {
            throw new KeycloakUserCreationException(response.getStatus());
        }

        String userId = response.getLocation().getPath().replaceAll(".*/([^/]+)$", "$1");

        // 2. SET PASSWORD
        CredentialRepresentation credential = new CredentialRepresentation();
        credential.setType(CredentialRepresentation.PASSWORD);
        credential.setValue(request.password());
        credential.setTemporary(false);

        keycloak.realm(keycloakRealm).users().get(userId).resetPassword(credential);

        // 3. ASSIGN 'PARTNER' ROLE AT 'telepresence' CLIENT LEVEL
        // We search for the internal UUID of the Keycloak client
        String clientUuid = keycloak.realm(keycloakRealm)
                .clients()
                .findByClientId("telepresence")
                .get(0)
                .getId();

        // We get the PARTNER role defined within that client
        RoleRepresentation partnerRole = keycloak.realm(keycloakRealm)
                .clients()
                .get(clientUuid)
                .roles()
                .get("PARTNER")
                .toRepresentation();

        // We assign the role to the user
        keycloak.realm(keycloakRealm)
                .users()
                .get(userId)
                .roles()
                .clientLevel(clientUuid)
                .add(List.of(partnerRole));

        // 4. PERSISTENCE IN LOCAL DATABASE
        Partner partner = new Partner();
        partner.setKeycloakId(userId);
        partner.setEmail(normalizedEmail);
        partner.setName(request.name().trim());
        Area area = areaService.findById(request.areaId().longValue());
        partner.setArea(area);
        partner.setAvailabilityStatus(PartnerAvailabilityStatus.available);
        partner.setTermsAccepted(request.termsAccepted());
        partner.setLanguage(request.language() != null ? request.language() : UserLanguage.es);
        partner.setPicDirectory(normalizePicDirectory(request.picDirectory()));
        partner.setRole(UserRole.partner);
        partner.setCreatedAt(Instant.now());

        Partner saved = partnerRepository.save(partner);

        return new RegisterPartnerResponse(
                saved.getId(),
                saved.getEmail(),
                saved.getName(),
                saved.getStatus(),
                saved.getLanguage(),
                saved.getCreatedAt(),
                saved.getTermsAccepted(),
                saved.getPicDirectory(),
                saved.getRole(),
                saved.getArea().getId().intValue(),
                saved.getAvailabilityStatus());
    }

    private String normalizePicDirectory(String path) {
        if (path == null)
            return null;
        String t = path.trim();
        return t.isEmpty() ? null : t;
    }
}

package com.synexis.management_service.service.impl;

import com.synexis.management_service.dto.request.RegisterPartnerRequest;
import com.synexis.management_service.dto.response.RegisterPartnerResponse;
import com.synexis.management_service.entity.Area;
import com.synexis.management_service.entity.Partner;
import com.synexis.management_service.entity.PartnerAvailabilityStatus;
import com.synexis.management_service.entity.UserLanguage;
import com.synexis.management_service.entity.UserRole;
import com.synexis.management_service.exception.EmailAlreadyExistsException;
import com.synexis.management_service.exception.KeycloakUserCreationException;
import com.synexis.management_service.repository.PartnerRepository;
import com.synexis.management_service.service.AreaService;
import com.synexis.management_service.service.PartnerService;

import jakarta.ws.rs.core.Response;

import java.time.Instant;
import java.util.List;

import org.keycloak.admin.client.Keycloak;
import org.keycloak.representations.idm.ClientRepresentation;
import org.keycloak.representations.idm.CredentialRepresentation;
import org.keycloak.representations.idm.RoleRepresentation;
import org.keycloak.representations.idm.UserRepresentation;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * Handles partner registration and related business operations.
 */
@Service
public class PartnerServiceImpl implements PartnerService {

    private String keycloakRealm = "synexis";

    private final PartnerRepository partnerRepository;
    private final Keycloak keycloak;
    private final AreaService areaService;

    public PartnerServiceImpl(PartnerRepository partnerRepository, Keycloak keycloak, AreaService areaService) {
        this.partnerRepository = partnerRepository;
        this.keycloak = keycloak;
        this.areaService = areaService;
    }

    @Override
    @Transactional
    public RegisterPartnerResponse registerPartner(RegisterPartnerRequest request) {

        String normalizedEmail = request.email().trim().toLowerCase();

        if (partnerRepository.existsByEmailIgnoreCase(normalizedEmail)) {
            throw new EmailAlreadyExistsException(normalizedEmail);
        }

        // Validate referenced area before creating external user in Keycloak.
        Area area = areaService.findById(request.areaId().longValue());

        UserRepresentation user = new UserRepresentation();
        user.setUsername(normalizedEmail);
        user.setEmail(normalizedEmail);
        user.setEnabled(true);
        user.setFirstName(request.name().trim());
        user.setLastName(request.name().trim());
        user.setEmailVerified(true);

        Response response = keycloak.realm(keycloakRealm).users().create(user);

        if (response.getStatus() == 409) {
            throw new EmailAlreadyExistsException(normalizedEmail);
        }
        if (response.getStatus() != 201) {
            throw new KeycloakUserCreationException(response.getStatus());
        }

        String userId = response.getLocation().getPath().replaceAll(".*/([^/]+)$", "$1");

        CredentialRepresentation credential = new CredentialRepresentation();
        credential.setType(CredentialRepresentation.PASSWORD);
        credential.setValue(request.password());
        credential.setTemporary(false);

        keycloak.realm(keycloakRealm).users().get(userId).resetPassword(credential);

        String clientUuid;
        try {
            List<ClientRepresentation> clients = keycloak.realm(keycloakRealm)
                    .clients()
                    .findByClientId("telepresence");

            if (clients == null || clients.isEmpty()) {
                throw new KeycloakUserCreationException("Keycloak client 'telepresence' not found in realm 'synexis'.");
            }

            clientUuid = clients.get(0).getId();

            RoleRepresentation partnerRole = keycloak.realm(keycloakRealm)
                    .clients()
                    .get(clientUuid)
                    .roles()
                    .get("PARTNER")
                    .toRepresentation();

            keycloak.realm(keycloakRealm)
                    .users()
                    .get(userId)
                    .roles()
                    .clientLevel(clientUuid)
                    .add(List.of(partnerRole));
        } catch (KeycloakUserCreationException ex) {
            throw ex;
        } catch (Exception ex) {
            throw new KeycloakUserCreationException("Failed to assign PARTNER role in Keycloak: " + ex.getMessage());
        }

        Partner partner = new Partner();
        partner.setKeycloakId(userId);
        partner.setEmail(normalizedEmail);
        partner.setName(request.name().trim());
        partner.setArea(area);
        partner.setAvailabilityStatus(PartnerAvailabilityStatus.available);
        partner.setTermsAccepted(request.termsAccepted());
        partner.setLanguage(request.language() != null ? request.language() : UserLanguage.es);
        partner.setPicDirectory(normalizePicDirectory(request.picDirectory()));
        partner.setRole(UserRole.partner);
        partner.setCreatedAt(Instant.now());

        Partner saved = partnerRepository.save(partner);

        return new RegisterPartnerResponse(
                saved.getId(),
                saved.getEmail(),
                saved.getName(),
                saved.getStatus(),
                saved.getLanguage(),
                saved.getCreatedAt(),
                saved.getTermsAccepted(),
                saved.getPicDirectory(),
                saved.getRole(),
                saved.getArea().getId().intValue(),
                saved.getAvailabilityStatus());
    }

    private String normalizePicDirectory(String path) {
        if (path == null)
            return null;
        String t = path.trim();
        return t.isEmpty() ? null : t;
    }
}

